from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if not search_results:
        return {}

    # Initialize aggregation structure
    aggregated_data = defaultdict(lambda: {
        "count": 0,
        "sum_scores": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf'),
        "results": []
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        metadata = result.metadata or {}
        group_value = metadata.get(group_by_field)

        # Handle missing group field - assign to 'unknown' group
        if group_value is None:
            group_value = "unknown"

        # Accumulate basic statistics
        group_data = aggregated_data[group_value]
        group_data["count"] += 1
        group_data["sum_scores"] += result.score
        group_data["max_score"] = max(group_data["max_score"], result.score)
        group_data["min_score"] = min(group_data["min_score"], result.score)
        group_data["results"].append(result)

    # Prepare final aggregated results
    final_results = {}
    for group_value, data in aggregated_data.items():
        # Calculate average score
        avg_score = data["sum_scores"] / data["count"] if data["count"] > 0 else 0.0

        # Create base statistics dictionary
        group_stats = {
            "count": data["count"],
            "avg_score": round(avg_score, 4),
            "max_score": round(data["max_score"], 4),
            "min_score": round(data["min_score"], 4),
            "total_score": round(data["sum_scores"], 4)
        }

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                try:
                    # Get the field value from the first result (assuming consistent field across group)
                    field_value = None
                    if data["count"] > 0:
                        sample_result = data["results"][0]
                        metadata = sample_result.metadata or {}
                        field_value = metadata.get(field_name)

                        # If field exists, apply the aggregation function
                        if field_value is not None:
                            if isinstance(field_value, (int, float)):
                                group_stats[field_name] = func([r.metadata.get(field_name) for r in data["results"]])
                            else:
                                # For non-numeric fields, use appropriate aggregation
                                values = [r.metadata.get(field_name) for r in data["results"]]
                                if func == len:
                                    group_stats[field_name] = len(values)
                                elif func == max:
                                    group_stats[field_name] = max(values, key=str)
                                elif func == min:
                                    group_stats[field_name] = min(values, key=str)
                                else:
                                    # Default to list of unique values for other functions
                                    group_stats[field_name] = list({v:None for v in values}.keys())
                except Exception as e:
                    # Log error but continue with existing stats
                    continue

        final_results[group_value] = group_stats

    return final_results

